using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// Exposes application configuration as an MCP resource.
/// </summary>
[McpServerResource(Name = "config://app",
    Description = "Returns the current application configuration")]
public static class ConfigResource
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["version"] = "1.0.0",
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaAccess"] = false,
        },
        ["maxRetries"] = 3,
    };

    [McpServerResourceTemplate(UriTemplate = "config://app",
        Name = "Application Config",
        Description = "Full application configuration as JSON",
        MimeType = "application/json")]
    public static string GetAppConfig()
    {
        return JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResourceTemplate(UriTemplate = "config://app/{section}",
        Name = "Configuration Section",
        Description = "A specific section of the application configuration",
        MimeType = "application/json")]
    public static string GetConfigSection(string section)
    {
        if (AppConfig.TryGetValue(section, out var value))
        {
            return JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true });
        }

        throw new McpException($"Configuration section '{section}' not found.");
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

/// <summary>
/// A simple tool that echoes a message back, demonstrating tool registration.
/// </summary>
[McpServerToolType]
public static class EchoTool
{
    [McpServerTool(Name = "echo"), Description("Echoes the provided message back")]
    public static string Echo([Description("The message to echo")] string message)
    {
        return $"Echo: {message}";
    }
}

